INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (1, 'Desa Sukajaya', 'Sukajaya', 'Kabupaten Bogor', -6.6189, 106.5123, 'Desa Sukajaya merupakan salah satu desa yang berada di Kecamatan Sukajaya, Kabupaten Bogor, Jawa Barat. Desa ini terletak di kawasan perbukitan dengan ketinggian sekitar 700–1.100 meter di atas permukaan laut (mdpl). Lingkungannya masih sangat asri dengan hamparan hutan, perkebunan rakyat, serta lahan pertanian yang luas. Curah hujan yang tinggi, udara yang sejuk dengan suhu rata-rata 20–28°C, serta tanah vulkanik yang subur menjadikan Desa Sukajaya sebagai wilayah yang sangat potensial untuk menghasilkan berbagai komoditas pertanian dan perkebunan berkualitas.');
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, desa_id) OVERRIDING SYSTEM VALUE VALUES (1, 'Pak Ahmad Rifa''i – Kelompok Tani Hutan Sukajaya', 'Pak Ahmad Rifa''i – Kelompok Tani Hutan Sukajaya', 'Kp. Cisarua RT 02/RW 04, Desa Sukajaya, Kec. Sukajaya, Kab. Bogor, Jawa Barat 16660', '6281234561101', '2011', 1);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (1, 'Madu Hutan Sukajaya', 68000, 41, 'https://images.unsplash.com/photo-1587049352846-4a222e784d38?w=600&q=80', 'Madu murni hasil lebah liar dari kawasan hutan Sukajaya.', '250 ml', '100% alami, kaya antioksidan.', 'Lebah mencari nektar dari bunga kaliandra, kopi, dan berbagai tanaman hutan yang tumbuh alami di perbukitan Sukajaya. Proses panen dilakukan secara hati-hati agar koloni lebah tetap lestari. Setiap tetes madu membawa cita rasa khas hutan pegunungan Bogor yang masih terjaga keasriannya.', 3, 1, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (2, 'Madu Kaliandra Premium', 125000, 98, 'https://images.unsplash.com/photo-1587049352846-4a222e784d38?w=600&q=80', 'Madu premium dari bunga kaliandra.', '500 ml', 'Aroma floral, kadar air rendah.', 'Saat musim bunga kaliandra mekar, lebah menghasilkan madu dengan aroma bunga yang khas dan rasa manis yang lembut. Varian ini hanya tersedia pada musim tertentu sehingga menjadi produk premium desa.', 3, 1, NOW());
