INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (24, 'Cookies Kopi Sukajaya', 32000, 42, 'https://images.unsplash.com/photo-1497935586351-b67a49e012bf?w=600&q=80', 'Kue kering dengan bubuk kopi robusta.', '180 gr', 'Aroma kopi khas Sukajaya.', 'Cookies ini dibuat menggunakan kopi robusta lokal yang disangrai sendiri oleh petani sehingga menghadirkan aroma kopi yang kuat dalam setiap gigitan.', 2, 12, NOW());
INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (2, 'Desa Tugu Utara', 'Cisarua', 'Kabupaten Bogor', -6.7023, 106.9512, 'Desa Tugu Utara terletak di kawasan Kecamatan Cisarua, Kabupaten Bogor, Jawa Barat, tepat di lereng Gunung Gede Pangrango dengan ketinggian sekitar 900–1.500 mdpl. Desa ini memiliki suhu rata-rata 18–24°C sepanjang tahun, udara yang sejuk, curah hujan tinggi, serta tanah vulkanik yang sangat subur. Kondisi alam tersebut menjadikan Desa Tugu Utara sebagai salah satu sentra pertanian hortikultura, perkebunan kopi, dan budidaya lebah madu di kawasan Puncak Bogor.');
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, desa_id) OVERRIDING SYSTEM VALUE VALUES (13, 'Pak Hendra Gunawan – Kelompok Tani Lebah Gunung Lestari', 'Pak Hendra Gunawan – Kelompok Tani Lebah Gunung Lestari', 'Kp. Gunung Mas RT 02/RW 03, Desa Tugu Utara, Kec. Cisarua, Kab. Bogor', '6281234561201', '2011', 2);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (25, 'Madu Kaliandra Tugu', 68000, 72, 'https://images.unsplash.com/photo-1471193945509-9ad0617afabf?w=600&q=80', 'Madu murni dari bunga Kaliandra yang tumbuh di lereng Puncak.', '250 ml', 'Aroma harum, kaya antioksidan.', 'Lebah mengumpulkan nektar dari ribuan bunga Kaliandra yang tumbuh di kawasan pegunungan Puncak. Udara yang bersih dan minim polusi menghasilkan madu dengan aroma bunga yang khas serta rasa manis alami. Setiap panen dilakukan secara hati-hati agar koloni lebah tetap terjaga.', 3, 13, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (26, 'Madu Multiflora Puncak', 120000, 29, 'https://images.unsplash.com/photo-1471193945509-9ad0617afabf?w=600&q=80', 'Madu dari berbagai bunga hutan pegunungan.', '500 ml', 'Rasa lebih kompleks.', 'Setiap musim berbunga menghasilkan karakter rasa yang berbeda sehingga tidak ada dua panen madu yang benar-benar sama. Inilah yang membuat madu multiflora menjadi favorit pecinta madu alami.', 3, 13, NOW());
