INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (3, 'Desa Penglipuran', 'Bangli', 'Kabupaten Bangli', -8.4522, 115.3524, 'Desa Penglipuran adalah salah satu desa adat di Bali yang sangat terkenal dengan kelestarian budaya, arsitektur tradisional, dan kebersihan lingkungannya. Secara geografis, desa ini terletak di Kecamatan Bangli, Kabupaten Bangli, Bali, pada ketinggian sekitar 600–700 mdpl dengan suhu sejuk 18–26°C. Desa adat ini dikelilingi oleh hutan bambu yang luas yang berfungsi sebagai daerah resapan air serta pelindung kelestarian desa. Selain bambu, tanah subur di Penglipuran juga mendukung budidaya pertanian seperti jeruk kintamani, kakao, sayuran kopi, dan lebah madu trigona.');
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, desa_id) OVERRIDING SYSTEM VALUE VALUES (25, 'Pak I Wayan Sudarma – Kelompok Tani Madu Penglipuran', 'Pak I Wayan Sudarma – Kelompok Tani Madu Penglipuran', 'Banjar Penglipuran, Desa Penglipuran, Kec. Bangli, Kab. Bangli, Bali 80619', '6281234561301', '2012', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (49, 'Madu Trigona Penglipuran', 75000, 95, 'https://images.unsplash.com/photo-1471193945509-9ad0617afabf?w=600&q=80', 'Madu murni dari lebah Trigona tanpa sengat dengan cita rasa manis sedikit asam.', '250 ml', 'Kaya propolis alami, antioksidan tinggi, dipanen tanpa merusak koloni lebah.', 'Di balik hutan bambu yang rindang, masyarakat Desa Penglipuran membudidayakan lebah Trigona secara alami. Lebah ini mengumpulkan nektar dari berbagai bunga liar, tanaman kopi, dan rempah yang tumbuh di lingkungan desa. Berkat udara yang sejuk dan ekosistem yang masih terjaga, madu yang dihasilkan memiliki aroma khas, rasa unik, dan kandungan propolis yang lebih tinggi dibanding madu biasa.', 3, 25, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (50, 'Madu Trigona Premium', 135000, 65, 'https://images.unsplash.com/photo-1471193945509-9ad0617afabf?w=600&q=80', 'Madu premium hasil panen terbatas.', '500 ml', 'Kadar air rendah, kualitas premium.', 'Setiap musim panen hanya sebagian kecil madu terbaik yang dipilih menjadi varian Premium. Madu dipanen secara manual tanpa merusak sarang sehingga kelestarian lebah tetap terjaga untuk generasi berikutnya.', 3, 25, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, desa_id) OVERRIDING SYSTEM VALUE VALUES (26, 'UMKM Arta Bali Herbal', 'UMKM Arta Bali Herbal', 'Banjar Tengah, Desa Penglipuran, Bangli', '6281234561302', '2019', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (51, 'Honey Lemon Bali', 45000, 80, 'https://images.unsplash.com/photo-1471193945509-9ad0617afabf?w=600&q=80', 'Minuman madu dengan lemon segar Bali.', '300 ml', 'Menyegarkan dan meningkatkan daya tahan tubuh.', 'Perpaduan madu Trigona dengan lemon lokal Bali menghasilkan minuman herbal yang banyak dinikmati wisatawan setelah berkeliling Desa Penglipuran.', 3, 26, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (52, 'Madu Jahe Herbal', 48000, 71, 'https://images.unsplash.com/photo-1471193945509-9ad0617afabf?w=600&q=80', 'Minuman herbal madu dan jahe merah.', '300 ml', 'Menghangatkan tubuh.', 'Jahe merah yang tumbuh di pekarangan warga dipadukan dengan madu Trigona sehingga menghasilkan minuman tradisional yang diwariskan turun-temurun oleh masyarakat Bali.', 3, 26, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, desa_id) OVERRIDING SYSTEM VALUE VALUES (27, 'Pak I Made Suarsa', 'Pak I Made Suarsa', 'Banjar Penglipuran Kaja, Desa Penglipuran', '6281234561303', '2008', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (53, 'Kopi Arabika Penglipuran', 85000, 84, 'https://images.unsplash.com/photo-1497935586351-b67a49e012bf?w=600&q=80', 'Kopi Arabika premium dataran tinggi Bali.', '250 gr', 'Aroma floral, body ringan, aftertaste manis.', 'Kopi ini tumbuh di dataran tinggi Bangli pada ketinggian sekitar 1.000 mdpl dengan suhu yang sejuk. Perbedaan suhu siang dan malam membuat buah kopi matang lebih lambat sehingga menghasilkan cita rasa floral dan sedikit citrus yang menjadi ciri khas kopi Bali.', 2, 27, NOW());
