INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (63, 'Sawi Hijau', 12000, 107, 'https://images.unsplash.com/photo-1540420773420-3366772f4999?w=600&q=80', 'Sayuran segar.', '300 gr', 'Tekstur renyah.', 'Udara sejuk desa membuat pertumbuhan sawi lebih lambat sehingga menghasilkan rasa yang lebih manis alami.', 5, 31, NOW());
